// Filter: only process 'opportunity' events.
// n8n v2 webhook wraps the POST body under .body — handle both layouts.
const raw  = $input.first().json;
const item = raw.body || raw;

if (item.event !== 'opportunity') {
  return [];
}

const profitPct = parseFloat(item.profit_pct) || 0;
const inrDelta  = parseFloat(item.inr_delta)  || 0;

return [{
  json: {
    event: item,
    profitPct,
    inrDelta,
    // claudeRequest omitted — Mock Claude node below doesn't need it
  }
}];

// ── MOCK CLAUDE (swap this node for the real HTTP Request when you have an API key) ──
//
// Logic mirrors what Claude would reason:
//   profit > threshold × 1.5  AND  > 2%  → lower (bot is too conservative)
//   profit < threshold × 1.05 AND  > 0   → raise (barely cleared the bar)
//   everything else                       → hold
//
const prev = $input.first().json;
const profitPct       = prev.profitPct || 0;
const currentThreshold = parseFloat(prev.event?.min_spread_pct || 0.015);

let action, newThreshold, reason;

if (profitPct > currentThreshold * 1.5 && profitPct > 0.02) {
  action       = 'lower';
  newThreshold = Math.max(0.012, Math.round(currentThreshold * 0.9 * 1000) / 1000);
  reason       = `Profit ${(profitPct * 100).toFixed(2)}% is well above threshold — room to be more aggressive`;
} else if (profitPct > 0 && profitPct < currentThreshold * 1.05) {
  action       = 'raise';
  newThreshold = Math.min(0.05, Math.round(currentThreshold * 1.1 * 1000) / 1000);
  reason       = `Profit barely cleared the bar — market thinner than expected, tighten up`;
} else {
  action       = 'hold';
  newThreshold = currentThreshold;
  reason       = profitPct <= 0
    ? `Trade had no profit — do not adjust threshold based on bad trade`
    : `Profit in expected range — no adjustment needed`;
}

// Return in Claude API response format so Parse node works unchanged when you swap in the real node.
return [{
  json: {
    content: [{
      type: 'text',
      text: JSON.stringify({ action, new_threshold: newThreshold, reason })
    }]
  }
}];

// Parse the (mock) Claude response and validate.
const claudeBody = $input.first().json;
const prev       = $('Filter and Build Prompt').first().json;

let action = 'hold';
let newThreshold = null;
let reason = 'Parse error';

try {
  const text = claudeBody.content?.[0]?.text || '';
  const cleaned = text.replace(/```json\n?/g, '').replace(/```/g, '').trim();
  const parsed = JSON.parse(cleaned);

  action       = parsed.action || 'hold';
  newThreshold = parseFloat(parsed.new_threshold);
  reason       = parsed.reason || '';

  if (!['lower', 'raise', 'hold'].includes(action)) action = 'hold';
  if (isNaN(newThreshold) || newThreshold < 0.012 || newThreshold > 0.05) {
    action = 'hold';
    reason = `Rejected: threshold ${newThreshold} out of allowed range [0.012, 0.05]`;
  }
} catch (e) {
  action = 'hold';
  reason = `JSON parse failed: ${e.message}`;
}

console.log(`[parse] action=${action} new_threshold=${newThreshold} reason=${reason}`);

return [{
  json: {
    action,
    newThreshold,
    reason,
    event: prev.event,
    profitPct: prev.profitPct,
    inrDelta: prev.inrDelta
  }
}];

// ── Replaces the Slack node for local testing ──
// In production: swap this for an HTTP Request node pointing at your Slack webhook.
// All results are visible in the n8n Execution Log (left sidebar → Executions).
const prev = $('Parse Claude Response').first().json;
const botReply = $input.first().json;

const msg = [
  `✅ THRESHOLD CHANGED`,
  `Trade:     ${prev.event?.symbol} ${prev.event?.direction}`,
  `Profit:    ${(prev.profitPct * 100).toFixed(3)}%   INR Δ ${prev.inrDelta >= 0 ? '+' : ''}${prev.inrDelta.toFixed(2)}`,
  `Action:    ${prev.action.toUpperCase()}`,
  `Applied:   ${(botReply.applied || []).join(', ')}`,
  `Reason:    ${prev.reason}`,
].join('\n');

console.log(msg);
return [{ json: { message: msg, applied: botReply.applied, action: prev.action } }];

